112→  async getBookmarks(
113→    token: string,
114→    userId: string,
115→    cursor: string | null = null,
116→    limit = 10,
117→  ): Promise<CursorPage<JournalItem>> {
118→    const params = new URLSearchParams();
119→    params.set('userId', userId);
120→    params.set('limit', String(limit));
121→    if (cursor) {
122→      params.set('before', cursor);
123→    }
124→
125→    return apiRequest<CursorPage<JournalItem>>(`/getBookmarks?${params.toString()}`, {
126→      method: 'GET',
127→      headers: {
128→        ...authHeaders(token),
129→      },
130→    });
131→  },
132→
133→  async getNotificationsCount(
134→    token: string,
135→    userId: string,
136→  ): Promise<{count?: number}> {
137→    const params = new URLSearchParams();
138→    params.set('userId', userId);
139→    return apiRequest<{count?: number}>(`/getCountNotifications?${params.toString()}`, {
140→      method: 'GET',
141→      headers: {
142→        ...authHeaders(token),
143→      },
144→    });
145→  },
146→
147→  async markNotificationRead(
148→    token: string,
149→    notifId: string,
150→    source?: NotificationSource,
151→  ): Promise<{message?: string}> {
152→    return apiRequest<{message?: string}>('/readNotification', {
153→      method: 'POST',
154→      headers: {
155→        ...authHeaders(token),
156→        'Content-Type': 'application/json',
157→      },
158→      body: JSON.stringify({notifId, source}),
159→    });
160→  },
161→
162→  async deleteNotification(
163→    token: string,
164→    notifId: string,
165→    source?: NotificationSource,
166→  ): Promise<{message?: string}> {
167→    const suffix = source
168→      ? `/deleteNotification/${encodeURIComponent(notifId)}?source=${encodeURIComponent(source)}`
169→      : `/deleteNotification/${encodeURIComponent(notifId)}`;
170→
171→    return apiRequest<{message?: string}>(suffix, {
172→      method: 'DELETE',
173→      headers: {
174→        ...authHeaders(token),
175→      },
176→    });
177→  },
178→
179→  async getUnreadNotifications(
180→    token: string,
181→    cursor: string | null = null,
182→    limit = 10,
